-- Lets now see how do different customer cohorts generate revenue and profit over time
-- with a monthly cohort it's easier to analyze trends. so that is why it is not yearly.

-- cohort montly activity rate:
--was a customer active in month N?
--among the original cohort, what % bought in month N exactly?

with cohort_base as (
    SELECT
        csum.customerkey,
        csum.cohort_month,
        Date_trunc('month',oe.orderdate) as order_month,
        oe.order_revenue,
        oe.order_profit
    from customer_summary csum
    join order_enriched oe
        on csum.customerkey=oe.customerkey
),

cohort_index as (
--calc month diff of actual order and cohort
    SELECT
        customerkey,
        cohort_month,
        order_month,
        order_revenue,
        order_profit,
        (
            DATE_PART('year', order_month) * 12 +
            DATE_PART('month', order_month)
        ) -
        (
            DATE_PART('year', cohort_month) * 12 +
            DATE_PART('month', cohort_month)
        ) as months_number
    From cohort_base
),

cohort_metrics as (
    Select
        cohort_month,
        months_number,
        count(distinct customerkey) as active_customers,
        sum(order_revenue) as cohort_revenue,
        sum(order_profit) as cohort_profit
    From cohort_index
    Group by cohort_month, months_number
),

cohort_size as (
--get original cohort sizes
    SELECT
        cohort_month,
        count(*) as cohort_size
    from customer_summary
    where first_purchase_date is not null
    group by cohort_month
)


Select
    cm.cohort_month,
    cm.months_number,
    cm.active_customers,
    cm.cohort_revenue,
    cm.cohort_profit,
    cs.cohort_size,
    ROUND(cm.active_customers*100.0/cs.cohort_size,2) as "monthly_activity_rate_%"
from cohort_metrics cm
join cohort_size cs
    on cm.cohort_month=cs.cohort_month
ORDER BY cm.cohort_month,cm.months_number





-- Avg lifetime profit by cohort:

SELECT
    cohort_month,
    COUNT(*) AS customers,
    ROUND(AVG(lifetime_revenue)::numeric,2) AS avg_lifetime_revenue,
    ROUND(AVG(lifetime_profit)::numeric,2) AS avg_lifetime_profit,
    ROUND(SUM(lifetime_profit)::numeric,2) AS total_lifetime_profit
FROM customer_summary
GROUP BY cohort_month
ORDER BY cohort_month;

